/**
 * Get samples for a specific voice/pad
 */
export function getSamplesForVoice(voiceId: number): LibrarySample[] {
  const categories = VOICE_CATEGORIES[voiceId] || [];
  return SAMPLE_LIBRARY.filter(sample => categories.includes(sample.category));
}

/**
 * Get a sample by ID
 */
export function getSampleById(id: string): LibrarySample | undefined {
  return SAMPLE_LIBRARY.find(sample => sample.id === id);
}

/**
 * Get all samples in a category
 */
export function getSamplesByCategory(category: SampleCategory): LibrarySample[] {
  return SAMPLE_LIBRARY.filter(sample => sample.category === category);
}

/**
 * Get all unique categories with sample counts
 */
export function getCategoryStats(): Record<SampleCategory, number> {
  const stats: Record<string, number> = {};
  SAMPLE_LIBRARY.forEach(sample => {
    stats[sample.category] = (stats[sample.category] || 0) + 1;
  });
  return stats as Record<SampleCategory, number>;
}
